{"code":"import json
import re

path_level5 = locals()['var_function-call-8552121385304934685']
path_patents = locals()['var_function-call-12122079112080214207']

with open(path_level5, 'r') as f:
    level5_list = json.load(f)
level5_symbols = set(item['symbol'] for item in level5_list)

with open(path_patents, 'r') as f:
    patent_data = json.load(f)

year_pattern = re.compile(r'\b(19|20)\d{2}\b')

years_found = set()
patents_with_matches = 0
total_patents = 0

sample_counts = {}

for row in patent_data:
    total_patents += 1
    f_date = row.get('filing_date')
    if not f_date:
        continue

    match = year_pattern.search(f_date)
    if not match:
        continue
    year = int(match.group(0))
    years_found.add(year)

    cpc_str = row.get('cpc')
    if not cpc_str:
        continue

    try:
        cpc_list = json.loads(cpc_str)
    except:
        continue

    matched = False
    for item in cpc_list:
        code = item.get('code', '')
        if len(code) >= 4:
            prefix = code[:4]
            if prefix in level5_symbols:
                matched = True
                if prefix not in sample_counts:
                    sample_counts[prefix] = {}
                sample_counts[prefix][year] = sample_counts[prefix].get(year, 0) + 1

    if matched:
        patents_with_matches += 1

print("__RESULT__:")
print(json.dumps({
    "min_year": min(years_found) if years_found else None,
    "max_year": max(years_found) if years_found else None,
    "total_patents": total_patents,
    "patents_with_matches": patents_with_matches,
    "sample_keys": list(sample_counts.keys())[:10],
    "sample_data": {k: sample_counts[k] for k in list(sample_counts.keys())[:2]}
}))
"}

{"code":"import json
import re

path_level5 = locals()['var_function-call-8552121385304934685']
path_patents = locals()['var_function-call-12122079112080214207']

with open(path_level5, 'r') as f:
    level5_list = json.load(f)
level5_symbols = set(item['symbol'] for item in level5_list)

with open(path_patents, 'r') as f:
    patent_data = json.load(f)

# Simplified regex
year_pattern = re.compile(r'(19|20)\d{2}')

counts = {} # {symbol: {year: count}}

for row in patent_data:
    f_date = row.get('filing_date')
    if not f_date:
        continue

    match = year_pattern.search(f_date)
    if not match:
        continue
    year = int(match.group(0))

    cpc_str = row.get('cpc')
    if not cpc_str:
        continue

    try:
        cpc_list = json.loads(cpc_str)
    except:
        continue

    current_patent_symbols = set()
    for item in cpc_list:
        code = item.get('code', '')
        if len(code) >= 4:
            prefix = code[:4]
            if prefix in level5_symbols:
                current_patent_symbols.add(prefix)

    for s in current_patent_symbols:
        if s not in counts:
            counts[s] = {}
        counts[s][year] = counts[s].get(year, 0) + 1

# Calculate EMA and find best year
alpha = 0.2
selected_symbols = []

for sym, year_counts in counts.items():
    years = sorted(year_counts.keys())
    if not years:
        continue

    start_year = years[0]
    end_year = years[-1]

    # We must ensure we cover up to 2022 if possible to check if it's the peak.
    # If the data stops before 2022, we can't say 2022 is the best year.
    if end_year < 2022:
        continue

    ema = 0
    max_ema = -1
    best_year = -1

    current_ema = None

    # Iterate from start_year to end_year.
    # Should we iterate to 2022 explicitly if end_year > 2022? Yes.
    # If end_year == 2022, we stop there.

    for y in range(start_year, end_year + 1):
        c = year_counts.get(y, 0)
        if current_ema is None:
            current_ema = c
        else:
            current_ema = alpha * c + (1 - alpha) * current_ema

        if current_ema > max_ema:
            max_ema = current_ema
            best_year = y

    if best_year == 2022:
        selected_symbols.append(sym)

print("__RESULT__:")
print(json.dumps(selected_symbols))
"}

